  if (reasoning === "low" || reasoning === "medium" || reasoning === "high") {
    return reasoning;
  }
  throw new AgentEvalConfigError({
    message: `--reasoning=${reasoning} is not supported when Claude is selected. Use: low, medium, high.`,
